DECLARE
    c CURSOR FOR SELECT order_id FROM orders;
    n NUMBER DEFAULT 0;
BEGIN
    FOR rec IN c DO
        LET oid NUMBER := rec.order_id;
        UPDATE orders
           SET order_total = (
                SELECT COALESCE(SUM(quantity * unit_price), 0)
                FROM order_items
                WHERE order_id = :oid)
         WHERE order_id = :oid;
        n := n + 1;
    END FOR;
    RETURN 'Recalculated ' || n || ' order totals (the slow way).';
END;
